'use client';

import React, { useState, useRef, use } from 'react';

interface PageProps {
  params: Promise<{
    lang: string;
  }>;
}

export default function RfqPage({ params }: PageProps) {
  const resolvedParams = use(params);
  const isFr = resolvedParams.lang === 'fr';

  const t = {
    title: isFr ? 'Portail RFQ - Demande de Devis Sécurisée' : 'Secure B2B RFQ Portal',
    subtitle: isFr 
      ? 'Chiffrez vos structures de charpentes métalliques industrielles sous 24-48h.'
      : 'Get an engineered price quotation within 24-48 hours. Secure file transmission.',
    step1: isFr ? 'Coordonnées' : 'Contact Details',
    step2: isFr ? 'Spécifications' : 'Specifications',
    step3: isFr ? 'Fichiers CAO' : 'CAD Drawings',
    step4: isFr ? 'Volume & Envoi' : 'Volume & Submit',
    company: isFr ? 'Société' : 'Company Name',
    contact: isFr ? 'Contact' : 'Contact Person',
    email: isFr ? 'Adresse Email' : 'Email Address',
    phone: isFr ? 'Téléphone' : 'Phone Number',
    grade: isFr ? 'Grade Acier Principal' : 'Primary Steel Grade',
    finish: isFr ? 'Traitement de surface' : 'Surface Finishing',
    rawSteel: isFr ? 'Brut' : 'Raw / Mill finished',
    primed: isFr ? 'Peinture Primaire' : 'Primed painted',
    galvanized: isFr ? 'Galvanisation à chaud (ISO 1461)' : 'Hot-Dip Galvanized (ISO 1461)',
    powderCoated: isFr ? 'Thermolaquage RAL' : 'Powder Coated RAL',
    tolerance: isFr ? 'Tolérances' : 'Tolerances',
    stdTolerance: isFr ? 'Standard (ISO 2768-m)' : 'Standard (ISO 2768-m)',
    fineTolerance: isFr ? 'Précise (ISO 2768-f)' : 'Fine (ISO 2768-f)',
    uploadAreaDefault: isFr
      ? 'Faites glisser vos fichiers de plans ici ou cliquez pour parcourir'
      : 'Drag and drop your engineering drawings here or click to browse',
    uploadAreaActive: isFr
      ? 'Déposez les fichiers pour démarrer l\'analyse sécurisée'
      : 'Drop files now to initialize secure binary verification',
    uploadHint: isFr 
      ? 'Formats : DXF, DWG, STEP, PDF (Taille max: 30 Mo)'
      : 'Supported formats: DXF, DWG, STEP, PDF (Max size: 30MB)',
    qty: isFr ? 'Quantité' : 'Required Quantity',
    zip: isFr ? 'Code Postal' : 'Delivery Zip Code',
    notes: isFr ? 'Instructions Particulières' : 'Special Instructions / Notes',
    btnBack: isFr ? 'Retour' : 'Back',
    btnNext: isFr ? 'Suivant' : 'Next',
    btnSubmit: isFr ? 'Soumettre la Demande' : 'Submit Quote Request',
    processing: isFr ? 'Vérification binaire du fichier...' : 'Executing Magic Number validation...',
    uploadingS3: isFr ? 'Transfert direct vers S3...' : 'Uploading directly to AWS S3 bucket...',
    successTitle: isFr ? 'Demande Transmise avec Succès !' : 'RFQ Submitted successfully!',
    successDesc: isFr
      ? 'Vos fichiers CAO ont été vérifiés sur notre serveur et envoyés sur notre bucket de stockage privé. Notre bureau d\'études enverra le devis sous 24-48h.'
      : 'CAD files verified and streamed to our private S3 bucket. Our engineering center will issue the Devis within 24-48h.'
  };

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    companyName: '',
    contactName: '',
    email: '',
    phone: '',
    steelGrade: 'S355J2+N',
    finishing: 'raw',
    tolerance: 'standard',
    quantity: 1,
    zipCode: '',
    notes: ''
  });

  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [fileError, setFileError] = useState('');
  const [statusMessage, setStatusMessage] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const nextStep = () => setStep(prev => prev + 1);
  const prevStep = () => setStep(prev => prev - 1);

  // Drag and Drop Event Handlers
  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    setFileError('');
    
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      processFile(e.dataTransfer.files[0]);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFileError('');
    if (e.target.files && e.target.files[0]) {
      processFile(e.target.files[0]);
    }
  };

  const processFile = (file: File) => {
    const validExtensions = ['dxf', 'dwg', 'step', 'stp', 'pdf'];
    const fileExt = file.name.split('.').pop()?.toLowerCase() || '';

    if (!validExtensions.includes(fileExt)) {
      setFileError(isFr ? 'Format non supporté. Seuls DXF, DWG, STEP, et PDF sont autorisés.' : 'Unsupported format. Only DXF, DWG, STEP, and PDF are allowed.');
      return;
    }
    if (file.size > 30 * 1024 * 1024) {
      setFileError(isFr ? 'Fichier trop lourd. Max 30 Mo.' : 'File exceeds size limit. Max 30MB allowed.');
      return;
    }
    setSelectedFile(file);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedFile) return;

    setSubmitting(false);
    setStatusMessage(t.processing);

    try {
      // 1. Request AWS S3 Presigned URL & validate header signatures
      const preUploadData = new FormData();
      preUploadData.append('filename', selectedFile.name);
      preUploadData.append('fileSize', String(selectedFile.size));
      preUploadData.append('mimeType', selectedFile.type || 'application/octet-stream');
      
      // Send a small chunk of the file (first 100 bytes) for server-side Magic Number check
      const headerChunk = selectedFile.slice(0, 100);
      preUploadData.append('headerChunk', headerChunk);

      const res = await fetch('/api/rfq', {
        method: 'POST',
        body: preUploadData
      });

      if (!res.ok) {
        const err = await res.json();
        setFileError(err.message || 'Validation failed.');
        return;
      }

      const { uploadUrl, fileKey } = await res.json();

      // 2. Direct upload from browser to private AWS S3 bucket
      setStatusMessage(t.uploadingS3);
      const s3UploadRes = await fetch(uploadUrl, {
        method: 'PUT',
        headers: {
          'Content-Type': selectedFile.type || 'application/octet-stream'
        },
        body: selectedFile
      });

      if (!s3UploadRes.ok) {
        setFileError('Direct S3 upload failed. Storage error.');
        return;
      }

      // 3. Complete submission to trigger CRM Webhook
      setStatusMessage(isFr ? 'Création de l\'opportunité dans le CRM...' : 'Registering B2B opportunity in CRM...');
      const completeRes = await fetch('/api/rfq', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ...formData,
          s3Key: fileKey,
          filename: selectedFile.name
        })
      });

      if (completeRes.ok) {
        setSubmitted(true);
      } else {
        setFileError('Failed to register lead in CRM.');
      }

    } catch (err) {
      console.error(err);
      setFileError('Network error connecting to API endpoints.');
    } finally {
      setStatusMessage('');
    }
  };

  if (submitted) {
    return (
      <div className="min-h-[80vh] flex items-center justify-center bg-steel-dark py-16 px-4">
        <div className="max-w-md w-full border border-emerald-500/30 rounded-lg p-8 text-center bg-steel-medium shadow-2xl">
          <div className="text-emerald-500 mb-6 flex justify-center">
            <svg viewBox="0 0 24 24" width="64" height="64" stroke="currentColor" strokeWidth="2.5" fill="none">
              <path d="M22 11.08V12a10 10 0 11-5.93-9.14" />
              <path d="M22 4L12 14.01l-3-3" />
            </svg>
          </div>
          <h2 className="text-2xl font-bold font-display text-white mb-4">{t.successTitle}</h2>
          <p className="text-slate-400 text-sm leading-relaxed mb-6">{t.successDesc}</p>
          <button onClick={() => { setStep(1); setSubmitted(false); setSelectedFile(null); }} className="w-full py-3 border border-slate-700 hover:border-slate-500 rounded bg-transparent text-white font-semibold transition duration-200">
            {isFr ? 'Faire une nouvelle demande' : 'Submit Another Request'}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-steel-dark py-16 px-4">
      <div className="max-w-3xl mx-auto">
        <div className="text-center mb-12">
          <h1 className="text-3xl sm:text-4xl font-bold font-display text-white mb-4">{t.title}</h1>
          <p className="text-slate-400">{t.subtitle}</p>
        </div>

        {/* Step Indicators */}
        <div className="flex justify-between items-center mb-12 relative px-4">
          <div className="absolute top-4 left-10 right-10 h-0.5 bg-slate-800 z-0" />
          {[t.step1, t.step2, t.step3, t.step4].map((label, idx) => {
            const isActive = step === idx + 1;
            const isCompleted = step > idx + 1;
            return (
              <div key={idx} className="flex flex-col items-center gap-2 z-10 relative">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm transition-all duration-300 ${
                  isActive 
                    ? 'bg-blue-600 text-white ring-4 ring-blue-500/20' 
                    : isCompleted
                      ? 'bg-emerald-600 text-white'
                      : 'bg-slate-900 border-2 border-slate-800 text-slate-500'
                }`}>
                  {idx + 1}
                </div>
                <span className={`text-[10px] sm:text-xs font-bold uppercase tracking-wider ${isActive ? 'text-blue-500' : isCompleted ? 'text-emerald-500' : 'text-slate-500'}`}>
                  {label.split('. ')[1] || label}
                </span>
              </div>
            );
          })}
        </div>

        {/* Form Container */}
        <div className="border border-slate-800 rounded-xl p-6 sm:p-10 bg-slate-900/50 backdrop-blur-md shadow-2xl relative">
          <form onSubmit={handleSubmit}>
            {step === 1 && (
              <div className="space-y-6">
                <div className="flex flex-col gap-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.company}</label>
                  <input required type="text" name="companyName" value={formData.companyName} onChange={handleInputChange} className="bg-slate-950 border border-slate-800 text-white px-4 py-3 rounded-lg focus:outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition" placeholder="e.g. Alstom SAS" />
                </div>
                <div className="flex flex-col gap-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.contact}</label>
                  <input required type="text" name="contactName" value={formData.contactName} onChange={handleInputChange} className="bg-slate-950 border border-slate-800 text-white px-4 py-3 rounded-lg focus:outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition" placeholder="e.g. Jean Dupont" />
                </div>
                <div className="flex flex-col gap-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.email}</label>
                  <input required type="email" name="email" value={formData.email} onChange={handleInputChange} className="bg-slate-950 border border-slate-800 text-white px-4 py-3 rounded-lg focus:outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition" placeholder="e.g. j.dupont@alstom.com" />
                </div>
                <div className="flex flex-col gap-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.phone}</label>
                  <input required type="tel" name="phone" value={formData.phone} onChange={handleInputChange} className="bg-slate-950 border border-slate-800 text-white px-4 py-3 rounded-lg focus:outline-none focus:border-blue-500 focus:ring-4 focus:ring-blue-500/10 transition" placeholder="e.g. +33 6 1234 5678" />
                </div>
              </div>
            )}

            {step === 2 && (
              <div className="space-y-6">
                <div className="flex flex-col gap-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.grade}</label>
                  <select name="steelGrade" value={formData.steelGrade} onChange={handleInputChange} className="bg-slate-950 border border-slate-800 text-white px-4 py-3 rounded-lg focus:outline-none focus:border-blue-500 transition">
                    <option value="S355J2+N">Steel Grade S355J2+N (Recommended)</option>
                    <option value="S235JR">Steel Grade S235JR</option>
                    <option value="Stainless 304L">Stainless Steel 304L</option>
                    <option value="Stainless 316L">Stainless Steel 316L (Inox)</option>
                  </select>
                </div>
                <div className="flex flex-col gap-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.finish}</label>
                  <select name="finishing" value={formData.finishing} onChange={handleInputChange} className="bg-slate-950 border border-slate-800 text-white px-4 py-3 rounded-lg focus:outline-none focus:border-blue-500 transition">
                    <option value="raw">{t.rawSteel}</option>
                    <option value="primed">{t.primed}</option>
                    <option value="galvanized">{t.galvanized}</option>
                    <option value="powder-coated">{t.powderCoated}</option>
                  </select>
                </div>
                <div className="flex flex-col gap-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.tolerance}</label>
                  <select name="tolerance" value={formData.tolerance} onChange={handleInputChange} className="bg-slate-950 border border-slate-800 text-white px-4 py-3 rounded-lg focus:outline-none focus:border-blue-500 transition">
                    <option value="standard">{t.stdTolerance}</option>
                    <option value="fine">{t.fineTolerance}</option>
                  </select>
                </div>
              </div>
            )}

            {step === 3 && (
              <div className="space-y-6">
                <div className="flex flex-col gap-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.step3}</label>
                  <div 
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                    onClick={() => fileInputRef.current?.click()}
                    className={`border-2 border-dashed rounded-lg py-12 px-6 text-center cursor-pointer transition duration-300 ${
                      isDragging 
                        ? 'border-blue-500 bg-blue-500/5 shadow-inner' 
                        : 'border-slate-800 bg-slate-950/40 hover:border-slate-700'
                    }`}
                  >
                    <div className="flex justify-center mb-4 text-blue-500">
                      <svg viewBox="0 0 24 24" width="48" height="48" stroke="currentColor" strokeWidth="1.5" fill="none">
                        <path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4M17 8l-5-5-5 5M12 3v12" />
                      </svg>
                    </div>
                    <p className="text-white font-semibold mb-2">
                      {selectedFile ? selectedFile.name : (isDragging ? t.uploadAreaActive : t.uploadAreaDefault)}
                    </p>
                    <p className="text-xs text-slate-500">{t.uploadHint}</p>
                    <input 
                      required={!selectedFile}
                      type="file" 
                      ref={fileInputRef} 
                      onChange={handleFileChange} 
                      style={{ display: 'none' }} 
                      accept=".dxf,.dwg,.step,.stp,.pdf"
                    />
                  </div>
                  {fileError && <p className="text-red-500 text-xs mt-2 font-semibold">❌ {fileError}</p>}
                  {selectedFile && !fileError && (
                    <p className="text-emerald-500 text-xs mt-2 font-semibold flex items-center gap-1">
                      ✔ {selectedFile.name} ({(selectedFile.size / (1024 * 1024)).toFixed(2)} MB)
                    </p>
                  )}
                </div>
              </div>
            )}

            {step === 4 && (
              <div className="space-y-6">
                <div className="flex flex-col gap-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.qty}</label>
                  <input required type="number" min="1" name="quantity" value={formData.quantity} onChange={handleInputChange} className="bg-slate-950 border border-slate-800 text-white px-4 py-3 rounded-lg focus:outline-none focus:border-blue-500 transition" />
                </div>
                <div className="flex flex-col gap-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.zip}</label>
                  <input required type="text" name="zipCode" value={formData.zipCode} onChange={handleInputChange} className="bg-slate-950 border border-slate-800 text-white px-4 py-3 rounded-lg focus:outline-none focus:border-blue-500 transition" placeholder="e.g. 69001 (Lyon)" />
                </div>
                <div className="flex flex-col gap-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider">{t.notes}</label>
                  <textarea rows={4} name="notes" value={formData.notes} onChange={handleInputChange} className="bg-slate-950 border border-slate-800 text-white px-4 py-3 rounded-lg focus:outline-none focus:border-blue-500 transition" placeholder="e.g. Weld certifications required, hot-dip zinc coating..." />
                </div>
              </div>
            )}

            {/* Form Actions */}
            <div className="flex mt-10 pt-6 border-t border-slate-800 justify-between">
              {step > 1 && (
                <button type="button" onClick={prevStep} className="px-6 py-2.5 border border-slate-800 hover:border-slate-700 rounded-lg bg-transparent text-white font-semibold transition">
                  {t.btnBack}
                </button>
              )}
              
              {step < 4 ? (
                <button 
                  type="button" 
                  onClick={nextStep} 
                  className="px-6 py-2.5 bg-amber-500 hover:bg-amber-600 rounded-lg text-slate-950 font-bold transition ml-auto"
                  disabled={step === 3 && !selectedFile}
                >
                  {t.btnNext}
                </button>
              ) : (
                <button 
                  type="submit" 
                  className="px-8 py-3 bg-amber-500 hover:bg-amber-600 rounded-lg text-slate-950 font-bold transition ml-auto flex items-center gap-2"
                  disabled={submitting}
                >
                  {submitting ? statusMessage : t.btnSubmit}
                </button>
              )}
            </div>
          </form>
        </div>
      </div>
    </div>
  );
}
